import type { GeneratedFile } from './types.js'

/**
 * Generates a barrel index.ts that re-exports everything from the other three
 * generated files so consumers can do:
 *
 *   import { getTasks, Task, configureClient } from './api'
 *
 * instead of knowing which sub-file each export lives in.
 */
export function generateIndexBarrel(): GeneratedFile {
  const content = [
    '// This file is auto-generated by @codewithagents/openapi-gen — do not edit',
    '',
    "export * from './models.js'",
    "export * from './client-config.js'",
    "export * from './client.js'",
    '',
  ].join('\n')

  return { filename: 'index.ts', content }
}
